descriptor.templateCss:
.ecs200-full-widget {
  position: relative;
  width: 100%;
  height: 100%;
  overflow: hidden;
}
.ecs200-full-widget {
      --cat-yellow: #FFCD11;
      --cat-black: #1a1a1a;
      --cat-dark: #2c2c2c;
      --cat-gray: #3d3d3d;
      --cat-light-gray: #e8e8e8;
      --cat-white: #ffffff;
      --cat-accent: #f5a623;
      --sidebar-width: 340px;
      --transition: 0.3s ease;
    }

    .ecs200-full-widget * { margin: 0; padding: 0; box-sizing: border-box; }

    .ecs200-full-widget {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
      background: #f0f2f5;
      color: var(--cat-black);
      display: flex;
      min-height: 100%;
    }

    /* Sidebar */
    .ecs200-full-widget .sidebar {
      width: var(--sidebar-width);
      background: var(--cat-black);
      color: var(--cat-white);
      display: flex;
      flex-direction: column;
      position: absolute;
      top: 0;
      left: 0;
      bottom: 0;
      z-index: 100;
      transition: transform var(--transition);
    }

    .ecs200-full-widget .sidebar-header {
      background: var(--cat-yellow);
      color: var(--cat-black);
      padding: 20px;
      text-align: center;
    }

    .ecs200-full-widget .sidebar-header h1 {
      font-size: 1.3rem;
      font-weight: 800;
      letter-spacing: 0.5px;
    }

    .ecs200-full-widget .sidebar-header .subtitle {
      font-size: 0.8rem;
      opacity: 0.7;
      margin-top: 4px;
    }

    .ecs200-full-widget .sidebar-search {
      padding: 12px 16px;
      border-bottom: 1px solid var(--cat-gray);
    }

    .ecs200-full-widget .sidebar-search input {
      width: 100%;
      padding: 10px 14px;
      border: none;
      border-radius: 8px;
      background: var(--cat-gray);
      color: var(--cat-white);
      font-size: 0.9rem;
      outline: none;
    }

    .ecs200-full-widget .sidebar-search input::placeholder { color: #888; }
    .ecs200-full-widget .sidebar-search input:focus { background: #4a4a4a; }

    .ecs200-full-widget .doc-list {
      flex: 1;
      overflow-y: auto;
      padding: 8px 0;
    }

    .ecs200-full-widget .doc-item {
      padding: 14px 20px;
      cursor: pointer;
      border-left: 4px solid transparent;
      transition: all var(--transition);
      display: flex;
      align-items: center;
      gap: 12px;
    }

    .ecs200-full-widget .doc-item:hover {
      background: var(--cat-dark);
      border-left-color: var(--cat-yellow);
    }

    .ecs200-full-widget .doc-item.active {
      background: var(--cat-dark);
      border-left-color: var(--cat-yellow);
    }

    .ecs200-full-widget .doc-icon {
      width: 40px;
      height: 40px;
      background: var(--cat-gray);
      border-radius: 8px;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      font-size: 1.1rem;
    }

    .ecs200-full-widget .doc-item.active .doc-icon { background: var(--cat-yellow); color: var(--cat-black); }

    .ecs200-full-widget .doc-info h3 {
      font-size: 0.85rem;
      font-weight: 600;
      line-height: 1.3;
    }

    .ecs200-full-widget .doc-info .doc-id {
      font-size: 0.7rem;
      color: #999;
      margin-top: 2px;
    }

    .ecs200-full-widget .doc-info .doc-pages {
      font-size: 0.7rem;
      color: var(--cat-yellow);
      margin-top: 2px;
    }

    /* Main content */
    .ecs200-full-widget .main {
      margin-left: var(--sidebar-width);
      flex: 1;
      min-height: 100%;
      overflow-y: auto;
    }

    .ecs200-full-widget .topbar {
      background: var(--cat-white);
      border-bottom: 1px solid #ddd;
      padding: 16px 32px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      position: sticky;
      top: 0;
      z-index: 50;
    }

    .ecs200-full-widget .topbar h2 {
      font-size: 1.2rem;
      font-weight: 700;
    }

    .ecs200-full-widget .topbar-actions {
      display: flex;
      gap: 10px;
    }

    .ecs200-full-widget .btn {
      padding: 10px 20px;
      border: none;
      border-radius: 8px;
      font-size: 0.85rem;
      font-weight: 600;
      cursor: pointer;
      transition: all var(--transition);
      display: inline-flex;
      align-items: center;
      gap: 8px;
      text-decoration: none;
    }

    .ecs200-full-widget .btn-primary {
      background: var(--cat-yellow);
      color: var(--cat-black);
    }

    .ecs200-full-widget .btn-primary:hover { background: #e6b800; transform: translateY(-1px); }

    .ecs200-full-widget .btn-secondary {
      background: var(--cat-light-gray);
      color: var(--cat-black);
    }

    .ecs200-full-widget .btn-secondary:hover { background: #d0d0d0; }

    .ecs200-full-widget .content {
      padding: 32px;
    }

    /* Dashboard */
    .ecs200-full-widget .dashboard-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
      gap: 20px;
      margin-bottom: 32px;
    }

    .ecs200-full-widget .stat-card {
      background: var(--cat-white);
      border-radius: 12px;
      padding: 24px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.06);
      display: flex;
      align-items: center;
      gap: 16px;
      transition: transform var(--transition), box-shadow var(--transition);
    }

    .ecs200-full-widget .stat-card:hover {
      transform: translateY(-2px);
      box-shadow: 0 4px 16px rgba(0,0,0,0.1);
    }

    .ecs200-full-widget .stat-icon {
      width: 52px;
      height: 52px;
      border-radius: 12px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 1.4rem;
      flex-shrink: 0;
    }

    .ecs200-full-widget .stat-info h4 { font-size: 0.8rem; color: #888; text-transform: uppercase; letter-spacing: 0.5px; }
    .ecs200-full-widget .stat-info .stat-value { font-size: 1.8rem; font-weight: 800; margin-top: 4px; }

    /* Document detail view */
    .ecs200-full-widget .doc-detail {
      display: none;
    }

    .ecs200-full-widget .doc-detail.active { display: block; }

    .ecs200-full-widget .doc-header-card {
      background: linear-gradient(135deg, var(--cat-black) 0%, var(--cat-dark) 100%);
      color: var(--cat-white);
      border-radius: 16px;
      padding: 32px;
      margin-bottom: 24px;
      position: relative;
      overflow: hidden;
    }

    .ecs200-full-widget .doc-header-card::after {
      content: '';
      position: absolute;
      top: -30px;
      right: -30px;
      width: 120px;
      height: 120px;
      background: var(--cat-yellow);
      border-radius: 50%;
      opacity: 0.1;
    }

    .ecs200-full-widget .doc-header-card .doc-title {
      font-size: 1.6rem;
      font-weight: 800;
      margin-bottom: 8px;
    }

    .ecs200-full-widget .doc-header-card .doc-number {
      font-size: 0.9rem;
      color: var(--cat-yellow);
      margin-bottom: 16px;
    }

    .ecs200-full-widget .doc-header-card .doc-summary {
      font-size: 0.95rem;
      line-height: 1.7;
      opacity: 0.9;
      max-width: 800px;
    }

    .ecs200-full-widget .doc-meta {
      display: flex;
      gap: 24px;
      margin-top: 20px;
      flex-wrap: wrap;
    }

    .ecs200-full-widget .meta-badge {
      background: rgba(255,255,255,0.1);
      padding: 8px 16px;
      border-radius: 20px;
      font-size: 0.8rem;
      display: flex;
      align-items: center;
      gap: 6px;
    }

    /* Sections */
    .ecs200-full-widget .sections-container {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(380px, 1fr));
      gap: 20px;
    }

    .ecs200-full-widget .section-card {
      background: var(--cat-white);
      border-radius: 12px;
      padding: 24px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.06);
      transition: all var(--transition);
      border-left: 4px solid var(--cat-yellow);
      cursor: pointer;
    }

    .ecs200-full-widget .section-card:hover {
      transform: translateY(-2px);
      box-shadow: 0 4px 16px rgba(0,0,0,0.1);
    }

    .ecs200-full-widget .section-header {
      display: flex;
      align-items: flex-start;
      gap: 12px;
      margin-bottom: 12px;
    }

    .ecs200-full-widget .section-num {
      background: var(--cat-yellow);
      color: var(--cat-black);
      font-weight: 800;
      font-size: 0.75rem;
      padding: 4px 10px;
      border-radius: 6px;
      flex-shrink: 0;
      min-width: 36px;
      text-align: center;
    }

    .ecs200-full-widget .section-title {
      font-size: 1rem;
      font-weight: 700;
      line-height: 1.3;
    }

    .ecs200-full-widget .section-desc {
      font-size: 0.85rem;
      color: #666;
      line-height: 1.6;
      margin-bottom: 12px;
    }

    .ecs200-full-widget .section-page {
      font-size: 0.75rem;
      color: #999;
      display: flex;
      align-items: center;
      gap: 4px;
    }

    .ecs200-full-widget .subsections {
      margin-top: 12px;
      padding-top: 12px;
      border-top: 1px solid #eee;
    }

    .ecs200-full-widget .subsection {
      padding: 8px 8px;
      font-size: 0.82rem;
      color: #555;
      display: flex;
      justify-content: space-between;
      align-items: center;
      cursor: pointer;
      border-radius: 6px;
      transition: all var(--transition);
    }

    .ecs200-full-widget .subsection:hover { color: var(--cat-black); background: #fff8e1; }

    .ecs200-full-widget .subsection .sub-page {
      color: #aaa;
      font-size: 0.75rem;
      white-space: nowrap;
    }

    .ecs200-full-widget .open-at-page {
      display: inline-flex;
      align-items: center;
      gap: 4px;
      background: var(--cat-yellow);
      color: var(--cat-black);
      font-size: 0.7rem;
      font-weight: 700;
      padding: 3px 10px;
      border-radius: 4px;
      text-decoration: none;
      transition: all var(--transition);
      white-space: nowrap;
    }

    .ecs200-full-widget .open-at-page:hover { background: #e6b800; transform: translateY(-1px); }

    .ecs200-full-widget .section-page-link {
      display: inline-flex;
      align-items: center;
      gap: 6px;
    }

    .ecs200-full-widget .section-page-link .open-at-page { margin-left: 8px; }

    /* Quick find */
    .ecs200-full-widget .quick-find-results {
      background: var(--cat-white);
      border-radius: 12px;
      padding: 24px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.06);
      margin-bottom: 24px;
      display: none;
    }

    .ecs200-full-widget .quick-find-results.visible { display: block; }

    .ecs200-full-widget .quick-find-results h3 {
      font-size: 1rem;
      margin-bottom: 16px;
      color: var(--cat-black);
    }

    .ecs200-full-widget .search-result-item {
      padding: 14px 16px;
      border-radius: 8px;
      margin-bottom: 8px;
      background: #f8f9fa;
      transition: all var(--transition);
      border-left: 3px solid transparent;
    }

    .ecs200-full-widget .search-result-item:hover { background: #fff8e1; border-left-color: var(--cat-yellow); }

    .ecs200-full-widget .result-header {
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
      gap: 12px;
    }

    .ecs200-full-widget .result-doc { font-size: 0.72rem; color: #888; margin-top: 4px; }
    .ecs200-full-widget .result-section { font-weight: 600; font-size: 0.9rem; }
    .ecs200-full-widget .result-desc { font-size: 0.8rem; color: #666; margin-top: 6px; line-height: 1.5; }

    .ecs200-full-widget .result-matches {
      margin-top: 8px;
      padding-top: 8px;
      border-top: 1px solid #eee;
      display: flex;
      flex-direction: column;
      gap: 4px;
    }

    .ecs200-full-widget .result-match-item {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 6px 10px;
      border-radius: 6px;
      font-size: 0.8rem;
      color: #555;
      cursor: pointer;
      transition: all var(--transition);
    }

    .ecs200-full-widget .result-match-item:hover { background: #fff3cd; }

    .ecs200-full-widget .result-match-item .match-title { flex: 1; }

    .ecs200-full-widget .result-doc-badge {
      display: inline-block;
      background: var(--cat-dark);
      color: var(--cat-yellow);
      font-size: 0.65rem;
      font-weight: 700;
      padding: 2px 8px;
      border-radius: 4px;
      margin-right: 6px;
    }

    /* Mobile menu toggle */
    .ecs200-full-widget .menu-toggle {
      display: none;
      position: absolute;
      top: 12px;
      left: 12px;
      z-index: 200;
      background: var(--cat-yellow);
      border: none;
      padding: 10px;
      border-radius: 8px;
      cursor: pointer;
      font-size: 1.2rem;
    }

    /* Overview tab */
    .ecs200-full-widget .overview-section { margin-bottom: 32px; }
    .ecs200-full-widget .overview-section h3 { font-size: 1.1rem; font-weight: 700; margin-bottom: 16px; }

    .ecs200-full-widget .doc-overview-card {
      background: var(--cat-white);
      border-radius: 12px;
      padding: 24px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.06);
      margin-bottom: 16px;
      cursor: pointer;
      transition: all var(--transition);
      border-left: 4px solid transparent;
    }

    .ecs200-full-widget .doc-overview-card:hover {
      transform: translateY(-2px);
      box-shadow: 0 4px 16px rgba(0,0,0,0.1);
      border-left-color: var(--cat-yellow);
    }

    .ecs200-full-widget .doc-overview-card h4 { font-size: 1.15rem; margin-bottom: 8px; }
    .ecs200-full-widget .doc-overview-card .doc-id-badge {
      display: inline-block;
      background: var(--cat-yellow);
      color: var(--cat-black);
      font-size: 0.7rem;
      font-weight: 700;
      padding: 3px 10px;
      border-radius: 4px;
      margin-bottom: 10px;
    }
    .ecs200-full-widget .doc-overview-card p { font-size: 0.88rem; color: #555; line-height: 1.7; }
    .ecs200-full-widget .doc-overview-card .summary-lead { font-size: 0.92rem; color: #333; font-weight: 500; margin-bottom: 12px; line-height: 1.6; }

    .ecs200-full-widget .key-topics {
      display: flex;
      gap: 8px;
      flex-wrap: wrap;
      margin-top: 12px;
    }

    .ecs200-full-widget .topic-tag {
      background: #f0f2f5;
      color: #555;
      font-size: 0.72rem;
      padding: 4px 10px;
      border-radius: 12px;
      font-weight: 500;
    }

    .ecs200-full-widget .detail-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
      gap: 16px;
      margin-top: 16px;
    }

    .ecs200-full-widget .detail-block {
      background: #f8f9fa;
      border-radius: 10px;
      padding: 16px;
      border-left: 3px solid var(--cat-yellow);
    }

    .ecs200-full-widget .detail-block h5 {
      font-size: 0.82rem;
      font-weight: 700;
      color: var(--cat-black);
      margin-bottom: 8px;
      text-transform: uppercase;
      letter-spacing: 0.3px;
    }

    .ecs200-full-widget .detail-block ul {
      list-style: none;
      padding: 0;
    }

    .ecs200-full-widget .detail-block ul li {
      font-size: 0.82rem;
      color: #555;
      padding: 3px 0;
      line-height: 1.5;
      display: flex;
      align-items: baseline;
      gap: 6px;
    }

    .ecs200-full-widget .detail-block ul li::before {
      content: '▸';
      color: var(--cat-yellow);
      font-weight: bold;
      flex-shrink: 0;
    }

    .ecs200-full-widget .spec-table {
      width: 100%;
      border-collapse: collapse;
      font-size: 0.8rem;
      margin-top: 8px;
    }

    .ecs200-full-widget .spec-table td {
      padding: 5px 8px;
      border-bottom: 1px solid #eee;
      vertical-align: top;
    }

    .ecs200-full-widget .spec-table td:first-child {
      font-weight: 600;
      color: var(--cat-black);
      white-space: nowrap;
      width: 40%;
    }

    .ecs200-full-widget .spec-table td:last-child {
      color: #555;
    }

    .ecs200-full-widget .section-preview {
      margin-top: 16px;
      padding-top: 16px;
      border-top: 1px solid #e8e8e8;
    }

    .ecs200-full-widget .section-preview h5 {
      font-size: 0.82rem;
      font-weight: 700;
      color: var(--cat-black);
      margin-bottom: 10px;
      text-transform: uppercase;
      letter-spacing: 0.3px;
    }

    .ecs200-full-widget .section-preview-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 6px;
    }

    .ecs200-full-widget .section-preview-item {
      font-size: 0.78rem;
      color: #555;
      padding: 5px 10px;
      background: #f8f9fa;
      border-radius: 6px;
      display: flex;
      align-items: center;
      gap: 6px;
      cursor: pointer;
      transition: background var(--transition);
    }

    .ecs200-full-widget .section-preview-item:hover { background: #fff3cd; }

    .ecs200-full-widget .section-preview-item .sp-num {
      font-weight: 700;
      color: var(--cat-black);
      min-width: 24px;
    }

    .ecs200-full-widget .xref-section {
      margin-top: 14px;
      padding-top: 12px;
      border-top: 1px solid #e8e8e8;
    }

    .ecs200-full-widget .xref-section h5 {
      font-size: 0.75rem;
      font-weight: 700;
      color: #888;
      margin-bottom: 8px;
      text-transform: uppercase;
      letter-spacing: 0.5px;
    }

    .ecs200-full-widget .xref-badges {
      display: flex;
      gap: 6px;
      flex-wrap: wrap;
    }

    .ecs200-full-widget .xref-badge {
      font-size: 0.7rem;
      background: var(--cat-dark);
      color: var(--cat-yellow);
      padding: 3px 10px;
      border-radius: 4px;
      cursor: pointer;
      transition: all var(--transition);
    }

    .ecs200-full-widget .xref-badge:hover { background: var(--cat-black); transform: translateY(-1px); }

    .ecs200-full-widget .overview-intro {
      background: var(--cat-white);
      border-radius: 12px;
      padding: 28px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.06);
      margin-bottom: 24px;
      border-left: 4px solid var(--cat-yellow);
    }

    .ecs200-full-widget .overview-intro h3 { font-size: 1.1rem; margin-bottom: 12px; }
    .ecs200-full-widget .overview-intro p { font-size: 0.9rem; color: #555; line-height: 1.7; }

    /* Scrollbar */
    .ecs200-full-widget ::-webkit-scrollbar { width: 6px; }
    .ecs200-full-widget ::-webkit-scrollbar-track { background: transparent; }
    .ecs200-full-widget ::-webkit-scrollbar-thumb { background: #ccc; border-radius: 3px; }
    .ecs200-full-widget .sidebar ::-webkit-scrollbar-thumb { background: #555; }

    /* Responsive */
    @media (max-width: 900px) {
    .ecs200-full-widget .sidebar { transform: translateX(-100%); }
    .ecs200-full-widget .sidebar.open { transform: translateX(0); }
    .ecs200-full-widget .main { margin-left: 0; }
    .ecs200-full-widget .menu-toggle { display: block; }
    .ecs200-full-widget .content { padding: 20px; }
    .ecs200-full-widget .sections-container { grid-template-columns: 1fr; }
    }

    /* Print */
    @media print {
    .ecs200-full-widget .sidebar, .ecs200-full-widget .topbar, .ecs200-full-widget .menu-toggle { display: none; }
    .ecs200-full-widget .main { margin-left: 0; }
    }

    .ecs200-full-widget .highlight { background: var(--cat-yellow); padding: 1px 4px; border-radius: 3px; }

    /* Tab navigation */
    .ecs200-full-widget .tab-nav {
      display: flex;
      gap: 4px;
      margin-bottom: 24px;
      background: var(--cat-white);
      padding: 4px;
      border-radius: 12px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.06);
    }

    .ecs200-full-widget .tab-btn {
      padding: 10px 20px;
      border: none;
      border-radius: 8px;
      background: transparent;
      font-size: 0.85rem;
      font-weight: 600;
      cursor: pointer;
      transition: all var(--transition);
      color: #666;
    }

    .ecs200-full-widget .tab-btn.active {
      background: var(--cat-yellow);
      color: var(--cat-black);
    }

    .ecs200-full-widget .tab-btn:hover:not(.active) { background: #f0f2f5; }

    /* Modbus Register View */
    .ecs200-full-widget .modbus-intro {
      background: var(--cat-white);
      border-radius: 12px;
      padding: 28px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.06);
      margin-bottom: 24px;
      border-left: 4px solid #17a2b8;
    }
    .ecs200-full-widget .modbus-intro h3 { font-size: 1.1rem; margin-bottom: 12px; color: var(--cat-black); }
    .ecs200-full-widget .modbus-intro p { font-size: 0.88rem; color: #555; line-height: 1.7; margin-bottom: 8px; }

    .ecs200-full-widget .conn-info-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 12px;
      margin-top: 16px;
    }
    .ecs200-full-widget .conn-info-box {
      background: #f8f9fa;
      border-radius: 8px;
      padding: 14px 18px;
      border-left: 3px solid var(--cat-yellow);
    }
